    46â†’// A key-value stream backed by raft
    47â†’type raftNode struct {
    48â†’	proposeC    <-chan string            // proposed messages (k,v)
    49â†’	confChangeC <-chan raftpb.ConfChange // proposed cluster config changes
    50â†’	commitC     chan<- *commit           // entries committed to log (k,v)
    51â†’	errorC      chan<- error             // errors from raft session
    52â†’
    53â†’	id          int      // client ID for raft session
    54â†’	peers       []string // raft peer URLs
    55â†’	join        bool     // node is joining an existing cluster
    56â†’	waldir      string   // path to WAL directory
    57â†’	snapdir     string   // path to snapshot directory
    58â†’	getSnapshot func() ([]byte, error)
    59â†’
    60â†’	confState     raftpb.ConfState
    61â†’	snapshotIndex uint64
    62â†’	appliedIndex  uint64
    63â†’
    64â†’	// raft backing for the commit/error channel
    65â†’	node        raft.Node
    66â†’	raftStorage *raft.MemoryStorage
    67â†’	wal         *wal.WAL
    68â†’
    69â†’	snapshotter      *snap.Snapshotter
    70â†’	snapshotterReady chan *snap.Snapshotter // signals when snapshotter is ready
    71â†’
    72â†’	snapCount uint64
    73â†’	transport *rafthttp.Transport
    74â†’	stopc     chan struct{} // signals proposal channel closed
    75â†’	httpstopc chan struct{} // signals http server to shutdown
    76â†’	httpdonec chan struct{} // signals http server shutdown complete
    77â†’
    78â†’	logger *zap.Logger
    79â†’}
