    83â†’// newRaftNode initiates a raft instance and returns a committed log entry
    84â†’// channel and error channel. Proposals for log updates are sent over the
    85â†’// provided the proposal channel. All log entries are replayed over the
    86â†’// commit channel, followed by a nil message (to indicate the channel is
    87â†’// current), then new log entries. To shutdown, close proposeC and read errorC.
    88â†’func newRaftNode(id int, peers []string, join bool, getSnapshot func() ([]byte, error), proposeC <-chan string,
    89â†’	confChangeC <-chan raftpb.ConfChange,
    90â†’) (<-chan *commit, <-chan error, <-chan *snap.Snapshotter) {
    91â†’	commitC := make(chan *commit)
    92â†’	errorC := make(chan error)
    93â†’
    94â†’	rc := &raftNode{
    95â†’		proposeC:    proposeC,
    96â†’		confChangeC: confChangeC,
    97â†’		commitC:     commitC,
    98â†’		errorC:      errorC,
    99â†’		id:          id,
   100â†’		peers:       peers,
   101â†’		join:        join,
   102â†’		waldir:      fmt.Sprintf("raftexample-%d", id),
   103â†’		snapdir:     fmt.Sprintf("raftexample-%d-snap", id),
   104â†’		getSnapshot: getSnapshot,
   105â†’		snapCount:   defaultSnapshotCount,
   106â†’		stopc:       make(chan struct{}),
   107â†’		httpstopc:   make(chan struct{}),
   108â†’		httpdonec:   make(chan struct{}),
   109â†’
   110â†’		logger: zap.NewExample(),
   111â†’
   112â†’		snapshotterReady: make(chan *snap.Snapshotter, 1),
   113â†’		// rest of structure populated after WAL replay
   114â†’	}
   115â†’	go rc.startRaft()
   116â†’	return commitC, errorC, rc.snapshotterReady
   117â†’}
