   119â†’func (rc *raftNode) saveSnap(snap raftpb.Snapshot) error {
   120â†’	walSnap := walpb.Snapshot{
   121â†’		Index:     snap.Metadata.Index,
   122â†’		Term:      snap.Metadata.Term,
   123â†’		ConfState: &snap.Metadata.ConfState,
   124â†’	}
   125â†’	// save the snapshot file before writing the snapshot to the wal.
   126â†’	// This makes it possible for the snapshot file to become orphaned, but prevents
   127â†’	// a WAL snapshot entry from having no corresponding snapshot file.
   128â†’	if err := rc.snapshotter.SaveSnap(snap); err != nil {
   129â†’		return err
   130â†’	}
   131â†’	if err := rc.wal.SaveSnapshot(walSnap); err != nil {
   132â†’		return err
   133â†’	}
   134â†’	return rc.wal.ReleaseLockTo(snap.Metadata.Index)
   135â†’}
