   137â†’func (rc *raftNode) entriesToApply(ents []raftpb.Entry) (nents []raftpb.Entry) {
   138â†’	if len(ents) == 0 {
   139â†’		return ents
   140â†’	}
   141â†’	firstIdx := ents[0].Index
   142â†’	if firstIdx > rc.appliedIndex+1 {
   143â†’		log.Fatalf("first index of committed entry[%d] should <= progress.appliedIndex[%d]+1", firstIdx, rc.appliedIndex)
   144â†’	}
   145â†’	if rc.appliedIndex-firstIdx+1 < uint64(len(ents)) {
   146â†’		nents = ents[rc.appliedIndex-firstIdx+1:]
   147â†’	}
   148â†’	return nents
   149â†’}
