   151â†’// publishEntries writes committed log entries to commit channel and returns
   152â†’// whether all entries could be published.
   153â†’func (rc *raftNode) publishEntries(ents []raftpb.Entry) (<-chan struct{}, bool) {
   154â†’	if len(ents) == 0 {
   155â†’		return nil, true
   156â†’	}
   157â†’
   158â†’	data := make([]string, 0, len(ents))
   159â†’	for i := range ents {
   160â†’		switch ents[i].Type {
   161â†’		case raftpb.EntryNormal:
   162â†’			if len(ents[i].Data) == 0 {
   163â†’				// ignore empty messages
   164â†’				break
   165â†’			}
   166â†’			s := string(ents[i].Data)
   167â†’			data = append(data, s)
   168â†’		case raftpb.EntryConfChange:
   169â†’			var cc raftpb.ConfChange
   170â†’			cc.Unmarshal(ents[i].Data)
   171â†’			rc.confState = *rc.node.ApplyConfChange(cc)
   172â†’			switch cc.Type {
   173â†’			case raftpb.ConfChangeAddNode:
   174â†’				if len(cc.Context) > 0 {
   175â†’					rc.transport.AddPeer(types.ID(cc.NodeID), []string{string(cc.Context)})
   176â†’				}
   177â†’			case raftpb.ConfChangeRemoveNode:
   178â†’				if cc.NodeID == uint64(rc.id) {
   179â†’					log.Println("I've been removed from the cluster! Shutting down.")
   180â†’					return nil, false
   181â†’				}
   182â†’				rc.transport.RemovePeer(types.ID(cc.NodeID))
   183â†’			}
   184â†’		}
   185â†’	}
   186â†’
   187â†’	var applyDoneC chan struct{}
   188â†’
   189â†’	if len(data) > 0 {
   190â†’		applyDoneC = make(chan struct{}, 1)
   191â†’		select {
   192â†’		case rc.commitC <- &commit{data, applyDoneC}:
   193â†’		case <-rc.stopc:
   194â†’			return nil, false
   195â†’		}
   196â†’	}
   197â†’
   198â†’	// after commit, update appliedIndex
   199â†’	rc.appliedIndex = ents[len(ents)-1].Index
   200â†’
   201â†’	return applyDoneC, true
   202â†’}
