   204â†’func (rc *raftNode) loadSnapshot() *raftpb.Snapshot {
   205â†’	if wal.Exist(rc.waldir) {
   206â†’		walSnaps, err := wal.ValidSnapshotEntries(rc.logger, rc.waldir)
   207â†’		if err != nil {
   208â†’			log.Fatalf("raftexample: error listing snapshots (%v)", err)
   209â†’		}
   210â†’		snapshot, err := rc.snapshotter.LoadNewestAvailable(walSnaps)
   211â†’		if err != nil && !errors.Is(err, snap.ErrNoSnapshot) {
   212â†’			log.Fatalf("raftexample: error loading snapshot (%v)", err)
   213â†’		}
   214â†’		return snapshot
   215â†’	}
   216â†’	return &raftpb.Snapshot{}
   217â†’}
