   219â†’// openWAL returns a WAL ready for reading.
   220â†’func (rc *raftNode) openWAL(snapshot *raftpb.Snapshot) *wal.WAL {
   221â†’	if !wal.Exist(rc.waldir) {
   222â†’		if err := os.Mkdir(rc.waldir, 0o750); err != nil {
