   226â†’		w, err := wal.Create(zap.NewExample(), rc.waldir, nil)
   227â†’		if err != nil {
   228â†’			log.Fatalf("raftexample: create wal error (%v)", err)
   229â†’		}
   230â†’		w.Close()
   231â†’	}
   232â†’
   233â†’	walsnap := walpb.Snapshot{}
   234â†’	if snapshot != nil {
   235â†’		walsnap.Index, walsnap.Term = snapshot.Metadata.Index, snapshot.Metadata.Term
   236â†’	}
   237â†’	log.Printf("loading WAL at term %d and index %d", walsnap.Term, walsnap.Index)
   238â†’	w, err := wal.Open(zap.NewExample(), rc.waldir, walsnap)
   239â†’	if err != nil {
   240â†’		log.Fatalf("raftexample: error loading wal (%v)", err)
   241â†’	}
   242â†’
   243â†’	return w
   244â†’}
