   246â†’// replayWAL replays WAL entries into the raft instance.
   247â†’func (rc *raftNode) replayWAL() *wal.WAL {
   248â†’	log.Printf("replaying WAL of member %d", rc.id)
   249â†’	snapshot := rc.loadSnapshot()
   250â†’	w := rc.openWAL(snapshot)
   251â†’	_, st, ents, err := w.ReadAll()
   252â†’	if err != nil {
   253â†’		log.Fatalf("raftexample: failed to read WAL (%v)", err)
   254â†’	}
   255â†’	rc.raftStorage = raft.NewMemoryStorage()
   256â†’	if snapshot != nil {
   257â†’		rc.raftStorage.ApplySnapshot(*snapshot)
   258â†’	}
   259â†’	rc.raftStorage.SetHardState(st)
   260â†’
   261â†’	// append to storage so raft starts at the right place in log
   262â†’	rc.raftStorage.Append(ents)
   263â†’
   264â†’	return w
   265â†’}
