   275â†’func (rc *raftNode) startRaft() {
   276â†’	if !fileutil.Exist(rc.snapdir) {
   277â†’		if err := os.Mkdir(rc.snapdir, 0o750); err != nil {
   278â†’			log.Fatalf("raftexample: cannot create dir for snapshot (%v)", err)
   279â†’		}
   280â†’	}
   281â†’	rc.snapshotter = snap.New(zap.NewExample(), rc.snapdir)
   282â†’
   283â†’	oldwal := wal.Exist(rc.waldir)
   284â†’	rc.wal = rc.replayWAL()
   285â†’
   286â†’	// signal replay has finished
   287â†’	rc.snapshotterReady <- rc.snapshotter
   288â†’
   289â†’	rpeers := make([]raft.Peer, len(rc.peers))
   290â†’	for i := range rpeers {
   291â†’		rpeers[i] = raft.Peer{ID: uint64(i + 1)}
   292â†’	}
   293â†’	c := &raft.Config{
   294â†’		ID:                        uint64(rc.id),
   295â†’		ElectionTick:              10,
   296â†’		HeartbeatTick:             1,
   297â†’		Storage:                   rc.raftStorage,
   298â†’		MaxSizePerMsg:             1024 * 1024,
   299â†’		MaxInflightMsgs:           256,
   300â†’		MaxUncommittedEntriesSize: 1 << 30,
   301â†’	}
   302â†’
   303â†’	if oldwal || rc.join {
   304â†’		rc.node = raft.RestartNode(c)
   305â†’	} else {
   306â†’		rc.node = raft.StartNode(c, rpeers)
   307â†’	}
   308â†’
   309â†’	rc.transport = &rafthttp.Transport{
   310â†’		Logger:      rc.logger,
   311â†’		ID:          types.ID(rc.id),
   312â†’		ClusterID:   0x1000,
   313â†’		Raft:        rc,
   314â†’		ServerStats: stats.NewServerStats("", ""),
   315â†’		LeaderStats: stats.NewLeaderStats(zap.NewExample(), strconv.Itoa(rc.id)),
   316â†’		ErrorC:      make(chan error),
   317â†’	}
   318â†’
   319â†’	rc.transport.Start()
   320â†’	for i := range rc.peers {
   321â†’		if i+1 != rc.id {
   322â†’			rc.transport.AddPeer(types.ID(i+1), []string{rc.peers[i]})
   323â†’		}
   324â†’	}
   325â†’
   326â†’	go rc.serveRaft()
   327â†’	go rc.serveChannels()
   328â†’}
