   344â†’func (rc *raftNode) publishSnapshot(snapshotToSave raftpb.Snapshot) {
   345â†’	if raft.IsEmptySnap(snapshotToSave) {
   346â†’		return
   347â†’	}
   348â†’
   349â†’	log.Printf("publishing snapshot at index %d", rc.snapshotIndex)
   350â†’	defer log.Printf("finished publishing snapshot at index %d", rc.snapshotIndex)
   351â†’
   352â†’	if snapshotToSave.Metadata.Index <= rc.appliedIndex {
   353â†’		log.Fatalf("snapshot index [%d] should > progress.appliedIndex [%d]", snapshotToSave.Metadata.Index, rc.appliedIndex)
   354â†’	}
   355â†’	rc.commitC <- nil // trigger kvstore to load snapshot
   356â†’
   357â†’	rc.confState = snapshotToSave.Metadata.ConfState
   358â†’	rc.snapshotIndex = snapshotToSave.Metadata.Index
   359â†’	rc.appliedIndex = snapshotToSave.Metadata.Index
   360â†’}
