   364â†’func (rc *raftNode) maybeTriggerSnapshot(applyDoneC <-chan struct{}) {
   365â†’	if rc.appliedIndex-rc.snapshotIndex <= rc.snapCount {
   366â†’		return
   367â†’	}
   368â†’
   369â†’	// wait until all committed entries are applied (or server is closed)
   370â†’	if applyDoneC != nil {
   371â†’		select {
   372â†’		case <-applyDoneC:
   373â†’		case <-rc.stopc:
   374â†’			return
   375â†’		}
   376â†’	}
   377â†’
   378â†’	log.Printf("start snapshot [applied index: %d | last snapshot index: %d]", rc.appliedIndex, rc.snapshotIndex)
   379â†’	data, err := rc.getSnapshot()
   380â†’	if err != nil {
   381â†’		log.Panic(err)
   382â†’	}
   383â†’	snap, err := rc.raftStorage.CreateSnapshot(rc.appliedIndex, &rc.confState, data)
   384â†’	if err != nil {
   385â†’		panic(err)
   386â†’	}
   387â†’	if err := rc.saveSnap(snap); err != nil {
   388â†’		panic(err)
   389â†’	}
   390â†’
   391â†’	compactIndex := uint64(1)
   392â†’	if rc.appliedIndex > snapshotCatchUpEntriesN {
   393â†’		compactIndex = rc.appliedIndex - snapshotCatchUpEntriesN
   394â†’	}
   395â†’	if err := rc.raftStorage.Compact(compactIndex); err != nil {
   396â†’		if !errors.Is(err, raft.ErrCompacted) {
   397â†’			panic(err)
   398â†’		}
   399â†’	} else {
   400â†’		log.Printf("compacted log at index %d", compactIndex)
   401â†’	}
   402â†’
   403â†’	rc.snapshotIndex = rc.appliedIndex
   404â†’}
