   406â†’func (rc *raftNode) serveChannels() {
   407â†’	snap, err := rc.raftStorage.Snapshot()
   408â†’	if err != nil {
   409â†’		panic(err)
   410â†’	}
   411â†’	rc.confState = snap.Metadata.ConfState
   412â†’	rc.snapshotIndex = snap.Metadata.Index
   413â†’	rc.appliedIndex = snap.Metadata.Index
   414â†’
   415â†’	defer rc.wal.Close()
   416â†’
   417â†’	ticker := time.NewTicker(100 * time.Millisecond)
   418â†’	defer ticker.Stop()
   419â†’
   420â†’	// send proposals over raft
   421â†’	go func() {
   422â†’		confChangeCount := uint64(0)
   423â†’
   424â†’		for rc.proposeC != nil && rc.confChangeC != nil {
   425â†’			select {
   426â†’			case prop, ok := <-rc.proposeC:
   427â†’				if !ok {
   428â†’					rc.proposeC = nil
   429â†’				} else {
   430â†’					// blocks until accepted by raft state machine
   431â†’					rc.node.Propose(context.TODO(), []byte(prop))
   432â†’				}
   433â†’
   434â†’			case cc, ok := <-rc.confChangeC:
   435â†’				if !ok {
   436â†’					rc.confChangeC = nil
   437â†’				} else {
   438â†’					confChangeCount++
   439â†’					cc.ID = confChangeCount
   440â†’					rc.node.ProposeConfChange(context.TODO(), cc)
   441â†’				}
   442â†’			}
   443â†’		}
   444â†’		// client closed channel; shutdown raft if not already
   445â†’		close(rc.stopc)
   446â†’	}()
   447â†’
   448â†’	// event loop on raft state machine updates
   449â†’	for {
   450â†’		select {
   451â†’		case <-ticker.C:
   452â†’			rc.node.Tick()
   453â†’
   454â†’		// store raft entries to wal, then publish over commit channel
   455â†’		case rd := <-rc.node.Ready():
   456â†’			// Must save the snapshot file and WAL snapshot entry before saving any other entries
   457â†’			// or hardstate to ensure that recovery after a snapshot restore is possible.
   458â†’			if !raft.IsEmptySnap(rd.Snapshot) {
   459â†’				rc.saveSnap(rd.Snapshot)
   460â†’			}
   461â†’			rc.wal.Save(rd.HardState, rd.Entries)
   462â†’			if !raft.IsEmptySnap(rd.Snapshot) {
   463â†’				rc.raftStorage.ApplySnapshot(rd.Snapshot)
   464â†’				rc.publishSnapshot(rd.Snapshot)
   465â†’			}
   466â†’			rc.raftStorage.Append(rd.Entries)
   467â†’			rc.transport.Send(rc.processMessages(rd.Messages))
   468â†’			applyDoneC, ok := rc.publishEntries(rc.entriesToApply(rd.CommittedEntries))
   469â†’			if !ok {
   470â†’				rc.stop()
   471â†’				return
   472â†’			}
   473â†’			rc.maybeTriggerSnapshot(applyDoneC)
   474â†’			rc.node.Advance()
   475â†’
   476â†’		case err := <-rc.transport.ErrorC:
   477â†’			rc.writeError(err)
   478â†’			return
   479â†’
   480â†’		case <-rc.stopc:
   481â†’			rc.stop()
   482â†’			return
   483â†’		}
   484â†’	}
   485â†’}
   486â†’
   487â†’// When there is a `raftpb.EntryConfChange` after creating the snapshot,
   488â†’// then the confState included in the snapshot is out of date. so We need
   489â†’// to update the confState before sending a snapshot to a follower.
   490â†’func (rc *raftNode) processMessages(ms []raftpb.Message) []raftpb.Message {
   491â†’	for i := 0; i < len(ms); i++ {
   492â†’		if ms[i].Type == raftpb.MsgSnap {
   493â†’			ms[i].Snapshot.Metadata.ConfState = rc.confState
   494â†’		}
   495â†’	}
   496â†’	return ms
   497â†’}
