   499â†’func (rc *raftNode) serveRaft() {
   500â†’	url, err := url.Parse(rc.peers[rc.id-1])
   501â†’	if err != nil {
   502â†’		log.Fatalf("raftexample: Failed parsing URL (%v)", err)
   503â†’	}
   504â†’
   505â†’	ln, err := newStoppableListener(url.Host, rc.httpstopc)
   506â†’	if err != nil {
   507â†’		log.Fatalf("raftexample: Failed to listen rafthttp (%v)", err)
   508â†’	}
   509â†’
   510â†’	err = (&http.Server{Handler: rc.transport.Handler()}).Serve(ln)
   511â†’	select {
   512â†’	case <-rc.httpstopc:
