   412â†’func recoverSnapshot(cfg config.ServerConfig, be backend.Backend, beExist bool, beHooks *serverstorage.BackendHooks, ci cindex.ConsistentIndexer) (*raftpb.Snapshot, backend.Backend, error) {
   413â†’	// Find a snapshot to start/restart a raft node
   414â†’	walSnaps, err := wal.ValidSnapshotEntries(cfg.Logger, cfg.WALDir())
   415â†’	if err != nil {
   416â†’		return nil, be, err
   417â†’	}
   418â†’
   419â†’	var snapshot *raftpb.Snapshot
   420â†’	if len(walSnaps) > 0 {
   421â†’		idx := len(walSnaps) - 1
   422â†’		snapshot = &raftpb.Snapshot{
   423â†’			Metadata: raftpb.SnapshotMetadata{
   424â†’				Term:  walSnaps[idx].Term,
   425â†’				Index: walSnaps[idx].Index,
   426â†’			},
   427â†’		}
   428â†’		if walSnaps[idx].ConfState != nil {
   429â†’			snapshot.Metadata.ConfState = *walSnaps[idx].ConfState
   430â†’		}
   431â†’		cfg.Logger.Info("constructed a snapshot from WAL record",
   432â†’			zap.Uint64("snapshot-index", snapshot.Metadata.Index),
   433â†’			zap.String("snapshot-size", humanize.Bytes(uint64(snapshot.Size()))),
   434â†’			zap.String("confState", snapshot.Metadata.ConfState.String()),
   435â†’			zap.Int("walSnaps-count", len(walSnaps)),
   436â†’		)
   437â†’	}
   438â†’
   439â†’	if snapshot != nil {
   440â†’		if be, err = serverstorage.RecoverSnapshotBackend(cfg, be, *snapshot, beExist, beHooks); err != nil {
   441â†’			cfg.Logger.Panic("failed to recover v3 backend from snapshot", zap.Error(err))
   442â†’		}
   443â†’		// A snapshot db may have already been recovered, and the old db should have
   444â†’		// already been closed in this case, so we should set the backend again.
   445â†’		ci.SetBackend(be)
   446â†’
   447â†’		if beExist {
   448â†’			// TODO: remove kvindex != 0 checking when we do not expect users to upgrade
   449â†’			// etcd from pre-3.0 release.
   450â†’			kvindex := ci.ConsistentIndex()
   451â†’			if kvindex < snapshot.Metadata.Index {
   452â†’				if kvindex != 0 {
   453â†’					return nil, be, fmt.Errorf("database file (%v index %d) does not match with snapshot (index %d)", cfg.BackendPath(), kvindex, snapshot.Metadata.Index)
   454â†’				}
   455â†’				cfg.Logger.Warn(
   456â†’					"consistent index was never saved",
   457â†’					zap.Uint64("snapshot-index", snapshot.Metadata.Index),
   458â†’				)
   459â†’			}
   460â†’		}
   461â†’	} else {
   462â†’		cfg.Logger.Info("No snapshot found. Recovering WAL from scratch!")
   463â†’	}
   464â†’	return snapshot, be, nil
   465â†’}
