   624â†’// openWALFromSnapshot reads the WAL at the given snap and returns the wal, its latest HardState and cluster ID, and all entries that appear
   625â†’// after the position of the given snap in the WAL.
   626â†’// The snap must have been previously saved to the WAL, or this call will panic.
   627â†’func openWALFromSnapshot(cfg config.ServerConfig, snapshot *raftpb.Snapshot) (*wal.WAL, *raftpb.HardState, []raftpb.Entry, *raftpb.Snapshot, *snapshotMetadata) {
   628â†’	var walsnap walpb.Snapshot
   629â†’	if snapshot != nil {
   630â†’		walsnap.Index, walsnap.Term = snapshot.Metadata.Index, snapshot.Metadata.Term
   631â†’	}
   632â†’	repaired := false
   633â†’	for {
   634â†’		w, err := wal.Open(cfg.Logger, cfg.WALDir(), walsnap)
   635â†’		if err != nil {
   636â†’			cfg.Logger.Fatal("failed to open WAL", zap.Error(err))
   637â†’		}
   638â†’		if cfg.UnsafeNoFsync {
   639â†’			w.SetUnsafeNoFsync()
   640â†’		}
   641â†’		wmetadata, st, ents, err := w.ReadAll()
   642â†’		if err != nil {
   643â†’			w.Close()
   644â†’			// we can only repair ErrUnexpectedEOF and we never repair twice.
   645â†’			if repaired || !errors.Is(err, io.ErrUnexpectedEOF) {
   646â†’				cfg.Logger.Fatal("failed to read WAL, cannot be repaired", zap.Error(err))
   647â†’			}
   648â†’			if !wal.Repair(cfg.Logger, cfg.WALDir()) {
   649â†’				cfg.Logger.Fatal("failed to repair WAL", zap.Error(err))
   650â†’			} else {
   651â†’				cfg.Logger.Info("repaired WAL", zap.Error(err))
   652â†’				repaired = true
   653â†’			}
   654â†’			continue
   655â†’		}
   656â†’		var metadata etcdserverpb.Metadata
   657â†’		pbutil.MustUnmarshal(&metadata, wmetadata)
   658â†’		id := types.ID(metadata.NodeID)
   659â†’		cid := types.ID(metadata.ClusterID)
   660â†’		meta := &snapshotMetadata{clusterID: cid, nodeID: id}
   661â†’		return w, &st, ents, snapshot, meta
   662â†’	}
   663â†’}
