   282â†’func maybeDefragBackend(cfg config.ServerConfig, be backend.Backend) error {
   283â†’	size := be.Size()
   284â†’	sizeInUse := be.SizeInUse()
   285â†’	freeableMemory := uint(size - sizeInUse)
   286â†’	thresholdBytes := cfg.BootstrapDefragThresholdMegabytes * 1024 * 1024
   287â†’	if freeableMemory < thresholdBytes {
   288â†’		cfg.Logger.Info("Skipping defragmentation",
   289â†’			zap.Int64("current-db-size-bytes", size),
   290â†’			zap.String("current-db-size", humanize.Bytes(uint64(size))),
   291â†’			zap.Int64("current-db-size-in-use-bytes", sizeInUse),
   292â†’			zap.String("current-db-size-in-use", humanize.Bytes(uint64(sizeInUse))),
   293â†’			zap.Uint("bootstrap-defrag-threshold-bytes", thresholdBytes),
   294â†’			zap.String("bootstrap-defrag-threshold", humanize.Bytes(uint64(thresholdBytes))),
   295â†’		)
   296â†’		return nil
   297â†’	}
   298â†’	return be.Defrag()
   299â†’}
