   575â†’func bootstrapWALFromSnapshot(cfg config.ServerConfig, snapshot *raftpb.Snapshot, ci cindex.ConsistentIndexer) *bootstrappedWAL {
   576â†’	wal, st, ents, snap, meta := openWALFromSnapshot(cfg, snapshot)
   577â†’	bwal := &bootstrappedWAL{
   578â†’		lg:       cfg.Logger,
   579â†’		w:        wal,
   580â†’		st:       st,
   581â†’		ents:     ents,
   582â†’		snapshot: snap,
   583â†’		meta:     meta,
   584â†’		haveWAL:  true,
   585â†’	}
   586â†’
   587â†’	if cfg.ForceNewCluster {
   588â†’		consistentIndex := ci.ConsistentIndex()
   589â†’		oldCommitIndex := bwal.st.Commit
   590â†’		// If only `HardState.Commit` increases, HardState won't be persisted
   591â†’		// to disk, even though the committed entries might have already been
   592â†’		// applied. This can result in consistent_index > CommitIndex.
   593â†’		//
   594â†’		// When restarting etcd with `--force-new-cluster`, all uncommitted
   595â†’		// entries are dropped. To avoid losing entries that were actually
   596â†’		// committed, we reset Commit to max(HardState.Commit, consistent_index).
   597â†’		//
   598â†’		// See: https://github.com/etcd-io/raft/pull/300 for more details.
   599â†’		bwal.st.Commit = max(oldCommitIndex, consistentIndex)
   600â†’
   601â†’		// discard the previously uncommitted entries
   602â†’		bwal.ents = bwal.CommitedEntries()
   603â†’		entries := bwal.NewConfigChangeEntries()
   604â†’		// force commit config change entries
   605â†’		bwal.AppendAndCommitEntries(entries)
   606â†’		cfg.Logger.Info(
   607â†’			"forcing restart member",
   608â†’			zap.String("cluster-id", meta.clusterID.String()),
   609â†’			zap.String("local-member-id", meta.nodeID.String()),
   610â†’			zap.Uint64("wal-commit-index", oldCommitIndex),
   611â†’			zap.Uint64("commit-index", bwal.st.Commit),
   612â†’		)
   613â†’	} else {
   614â†’		cfg.Logger.Info(
   615â†’			"restarting local member",
   616â†’			zap.String("cluster-id", meta.clusterID.String()),
   617â†’			zap.String("local-member-id", meta.nodeID.String()),
   618â†’			zap.Uint64("commit-index", bwal.st.Commit),
   619â†’		)
   620â†’	}
   621â†’	return bwal
   622â†’}
