   669â†’func bootstrapNewWAL(cfg config.ServerConfig, cl *bootstrappedCluster) *bootstrappedWAL {
   670â†’	metadata := pbutil.MustMarshal(
   671â†’		&etcdserverpb.Metadata{
   672â†’			NodeID:    uint64(cl.nodeID),
   673â†’			ClusterID: uint64(cl.cl.ID()),
   674â†’		},
   675â†’	)
   676â†’	w, err := wal.Create(cfg.Logger, cfg.WALDir(), metadata)
   677â†’	if err != nil {
   678â†’		cfg.Logger.Panic("failed to create WAL", zap.Error(err))
   679â†’	}
   680â†’	if cfg.UnsafeNoFsync {
   681â†’		w.SetUnsafeNoFsync()
   682â†’	}
