   687â†’}
   688â†’
   689â†’type bootstrappedWAL struct {
   690â†’	lg *zap.Logger
   691â†’
   692â†’	haveWAL  bool
   693â†’	w        *wal.WAL
   694â†’	st       *raftpb.HardState
