   700â†’func (wal *bootstrappedWAL) MemoryStorage() *raft.MemoryStorage {
   701â†’	s := raft.NewMemoryStorage()
   702â†’	if wal.snapshot != nil {
   703â†’		s.ApplySnapshot(*wal.snapshot)
   704â†’	}
   705â†’	if wal.st != nil {
   706â†’		s.SetHardState(*wal.st)
   707â†’	}
   708â†’	if len(wal.ents) != 0 {
   709â†’		s.Append(wal.ents)
   710â†’	}
   711â†’	return s
   712â†’}
