   714â†’func (wal *bootstrappedWAL) CommitedEntries() []raftpb.Entry {
   715â†’	for i, ent := range wal.ents {
   716â†’		if ent.Index > wal.st.Commit {
   717â†’			wal.lg.Info(
   718â†’				"discarding uncommitted WAL entries",
   719â†’				zap.Uint64("entry-index", ent.Index),
   720â†’				zap.Uint64("commit-index-from-wal", wal.st.Commit),
   721â†’				zap.Int("number-of-discarded-entries", len(wal.ents)-i),
   722â†’			)
   723â†’			return wal.ents[:i]
   724â†’		}
   725â†’	}
   726â†’	return wal.ents
   727â†’}
