   729â†’func (wal *bootstrappedWAL) NewConfigChangeEntries() []raftpb.Entry {
   730â†’	return serverstorage.CreateConfigChangeEnts(
   731â†’		wal.lg,
   732â†’		serverstorage.GetEffectiveNodeIDsFromWALEntries(wal.lg, wal.snapshot, wal.ents),
   733â†’		uint64(wal.meta.nodeID),
   734â†’		wal.st.Term,
   735â†’		wal.st.Commit,
   736â†’	)
   737â†’}
