   739â†’func (wal *bootstrappedWAL) AppendAndCommitEntries(ents []raftpb.Entry) {
   740â†’	wal.ents = append(wal.ents, ents...)
   741â†’	err := wal.w.Save(raftpb.HardState{}, ents)
   742â†’	if err != nil {
